from smolagents import tool

@tool
def retrieve_docs(query: str) -> str:
    """Retrieve relevant documents from vector DB."""
    # Simulated FAISS/ChromaDB lookup
    docs = vector_db.similarity_search(query, k=3)
    return "\n".join([doc.page_content for doc in docs])

chatbot = CodeAgent(tools=[retrieve_docs], memory=memory)

from smolagents import LLM

classifier = LLM(model="huggingface/distilbert-base-uncased")

async def route_intent(message: str):
    intent = await classifier.classify(message)  # 'rag' | 'reason' | 'general'
    if intent == 'rag':
        agent = rag_agent
    else:
        agent = chatbot
    return await agent.run(message)
